-- Este script actualiza el contenido de las 6 noticias para incluir ricos enlaces internos (SEO)
-- a destinos y tours de la web.

UPDATE blog_posts 
SET content = '<p><a href="/destinos/marrakech"><strong>Marrakech</strong></a> es una ciudad que despierta los sentidos desde el primer momento en que asomas por la Medina. Para aprovechar al máximo tus 3 días y explorar con nuestros <a href="/tours">tours guiados</a>, te proponemos un itinerario pensado para enamorarte de la <em>Ciudad Roja</em>.</p>
  <h3>Día 1: El Corazón de la Medina</h3>
  <p>Comienza tu viaje en la vibrante Plaza Jemaa el-Fna. Déjate atrapar por los encantadores de serpientes, los puestos de jugo fresco y adéntrate en los zocos. Piérdete (literalmente) por sus estrechos callejones donde artesanos y tejedores exponen su trabajo. Por la tarde, visita la emblemática Mezquita Koutoubia y termina cenando en una de las terrazas.</p>
  <h3>Día 2: Palacios y Relajación</h3>
  <p>Aprovecha la mañana para descubrir la riqueza arquitectónica del Palacio de la Bahía. Maravíllate con la artesanía de los techos tallados. Luego, desconecta del bullicio disfrutando de un auténtico hammam marroquí, un baño de vapor ritual que renovará cuerpo y mente.</p>
  <h3>Día 3: Oasis en la Ciudad</h3>
  <p>El último día reserva una visita a los bellísimos Jardines Majorelle, el colorido retiro que te transportará a un ambiente de tranquilidad. Por la tarde, piérdete en la contemporaneidad de la Ville Nouvelle, donde podrás comprar recuerdos únicos antes del retorno.</p>'
WHERE slug = 'que-ver-en-marrakech-en-3-dias';

UPDATE blog_posts 
SET content = '<p>Una de las preguntas más frecuentes al planificar un viaje a Marruecos es en qué zona del desierto vivir la mágica experiencia del campamento beduino. Principalmente, existen dos opciones populares entre nuestros <a href="/tours">Tours por el Desierto</a>: <strong>Erg Chebbi (<a href="/destinos/desierto-de-merzouga">Merzouga</a>)</strong> y <strong>Erg Chigaga (Zagora)</strong>.</p>
  <h3>Merzouga (Erg Chebbi): Las dunas inmensas</h3>
  <p>Si la imagen que tienes en mente son grandes dunas de arena rojiza ondulantes hasta el horizonte, <a href="/destinos/desierto-de-merzouga">Merzouga</a> es tu destino. Ideal para los que buscan la auténtica postal que evocan películas del Sahara. Sin embargo, dada su lejanía desde <a href="/destinos/marrakech">Marrakech</a> (a un promedio de 9-10 horas), requerirás de al menos 3 días para un viaje.</p>
  <h3>Zagora: El desierto árido y cercano</h3>
  <p>Situado más cerca de Marrakech, llegar a Zagora toma alrededor de 7 horas en total. Zagora carece de las gigantes dunas características. Su desierto es más bien árido y pedregoso, aunque cuenta con hermosos oasis y ofrece igualmente el espectacular manto de estrellas nocturno.</p>
  <p><strong>El Veredicto:</strong> Opta por Merzouga si buscas dunas espectaculares. Revisa nuestros <a href="/tours">Catálogos de Viajes</a> para encontrar el que mejor encaje con tus días.</p>'
WHERE slug = 'desierto-merzouga-o-zagora';

UPDATE blog_posts 
SET content = '<p><a href="/destinos">Marruecos</a> no solo es un festín visual de colores, texturas y arquitectura magnífica, su <strong>oferta culinaria es una de las más ricas del norte africano</strong>. Los intensos aromas de especias y la fusión dulce-salado hacen de su comida toda una experiencia en todos nuestros <a href="/tours">viajes organizados</a>.</p>
  <h3>1. El Tajine</h3>
  <p>Es, indiscutiblemente, el plato omnipresente. El Tajine es un estofado especiado sensacional que puede ser pollo con limones encurtidos y olivas, o bien cordero glaseado con ciruelas y almendras tostadas.</p>
  <h3>2. El Cuscús Tradicional</h3>
  <p>Para los marroquíes, el cuscús es algo casi sagrado que se consume en su versión más elaborada los viernes. Es semolina trabajada al vapor incansablemente junto a caldos aromáticos y vegetales asados.</p>
  <h3>3. Pastilla (La Bastila)</h3>
  <p>La máxima sorpresa para quienes lo descubren por primera y genial vez. Es una tarta envuelta en papel filo, crujiente, horneada; rellena con fina carne confitada y coronada con azúcar glas.</p>
  <h3>4. Harira</h3>
  <p>Una reconfortante, aromática y vigorosa sopa con base elaborada a partir de tomates y legumbres. Rompe el ayuno del Ramadán debido a lo reconfortante que resulta a todas luces.</p>
  <h3>5. Té de Menta y Pastas</h3>
  <p>Beber té de verde menta es lo más cercano a la bebida oficial de Marruecos. No vayas a olvidar coronarlo con una rica variedad de panecillos y pastas basadas en almendra.</p>'
WHERE slug = 'gastronomia-marroqui-platos-tipicos';

UPDATE blog_posts 
SET content = '<p>Mientras que en la mayoría de grandes destinos mundiales los viajeros se decantan por un estandarizado resort, <a href="/destinos">Marruecos</a> brilla en todo su esplendor al brindarte la inmejorable oportunidad de experimentar toda la enorme riqueza y la hospitalidad dentro de en un <strong>Riad</strong>. Muchos de nuestros <a href="/coleccion/viajes-norte-de-marruecos">viajes por el norte</a> y expediciones al sur incluyen estancias en Riads seleccionados.</p>
  <h3>¿Qué es un Riad realmente?</h3>
  <p>Eran viviendas, muchas veces palacetes tradicionales urbanos, pertenecientes a miembros adinerados. Su concepto esencial es que están orientados arquitectónicamente hacia un majestuoso patio central bellísimamente adornado; es un oasis escondido por completo tras puertas impenetrables.</p>
  <h3>La paz total dentro del caos</h3>
  <p>En el Riad rige la hospitalidad, y este tipo particular y asombroso de estancias brindan todo un increíble abanico desde dormitorios modestos hasta espectaculares espacios cargados con zellige, fuentes interiores y frondosos techos.</p>
  <h3>El desayuno en su terraza... simplemente único</h3>
  <p>Para redondear tu experiencia al cien por ciento con <a href="/contacto">nuestro servicio de calidad</a>, los Riads modernos conllevan acceso a idílicas terrazas llenas de almohadones, ideales para reposar luego de arduas caminatas y donde la mañana inicia con exquisitos ritos brindados de cafés potentes.</p>'
WHERE slug = 'guia-para-alojarte-en-riad';

UPDATE blog_posts 
SET content = '<p>Incrustada delicadamente sobre un telón de montañas verdísimas se sitúa <a href="/destinos/chefchaouen">Chefchaouen</a> (o Chaouen), afamada e inconfundible por un hermoso distintivo: prácticamente todas las estructuras irradian gamas que viran de índigos a azules deslumbrantes. Forma parte primordial de muchos <a href="/coleccion/viajes-norte-de-marruecos">Tours y Viajes al Norte</a>.</p>
  <h3>¿De dónde proviene ese característico color?</h3>
  <p>Aunque diversas corrientes folclóricas indican que sirve para frenar las grandes olas de mosquitos en el calor estival, se impulsó enormemente en las pasadas décadas recién en 1930 aproximadamente propiciados de manera muy influyente gracias a migrantes sefardís.</p>
  <h3>No te puedes perder</h3>
  <ul>
    <li>Desempolva las piernas por absolutamente toda la <em>Medina peatonal</em> donde cualquier pequeño adarve luce de portada.</li>
    <li>Conecta con la pacífica pero viva plazoleta arbolada central <em>Uta el Hammam</em>.</li>
    <li>Reserva uno de nuestros <a href="/tours">Tours especializados</a> para empaparte de su cultura guiado por auténticos locales.</li>
  </ul>'
WHERE slug = 'chefchaouen-el-pueblo-azul';

UPDATE blog_posts 
SET content = '<p>El grandísimo y siempre apasionante salto geográfico hacia el Magreb no debiese nunca tomarte con baja preparación al encarar tu aventura por <a href="/destinos">Marruecos</a> con nuestros <a href="/tours">Circuitos Completos</a>.</p>
  <h3>1. El clima no siempre es un inmenso horno</h3>
  <p>Cuidado si tu expedición o salidas están fijadas alrededor de pleno invierno en locaciones próximas a faldas imponentes de montañas. Empaca estratégicamente por capas según latitudes.</p>
  <h3>2. La regla oro en todo zoco: El noble arte del regateo</h3>
  <p>El margen idóneo propiciado por grandes rebajas y sana lúdica gira a que lleguen y converjan juntos a saldos medianos a satisfacción a tu contraoferta con gran respeto. No aceptes siempre el primer precio en <a href="/destinos/marrakech">Marrakech</a> o Fez.</p>
  <h3>3. Las muestras fotográficas y las personas</h3>
  <p>Es altamente deshonroso fotografiar de cerca sin consentimiento. Sonríe cálidamente y pregunta mediante la cortesía gestual pidiendo total aprobación del ser en sí para tan preciada toma.</p>
  <h3>4. Consumo de alimentos y agua</h3>
  <p>En las rutas de los principales <a href="/tours">tours turísticos</a> todo es seguro, pero mantente completamente firme requiriendo bebida embotellada y evita hielos sueltos. ¡Marruecos te fascinará a ciencia cierta!</p>'
WHERE slug = 'consejos-viajar-a-marruecos';
